return $input.all().map(item => {
  const raw = item.json.response || "";

  const cleaned = raw
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/```\s*$/i, "")
    .trim();

  try {
    const parsed = JSON.parse(cleaned);
    return { json: { ...parsed, account_id: item.json.account_id } };
  } catch (e) {
    return {
      json: {
        memo: {
          parse_error: true,
          version: "v1",
          source: "demo_call",
          account_id: item.json.account_id
        },
        account_id: item.json.account_id
      }
    };
  }
});

return $input.all().map(item => {
  // Pass through parse_error items without crashing
  if (item.json.memo?.parse_error === true) {
    return {
      json: {
        account_id: item.json.account_id,
        spec_generated: false,
        memo: item.json.memo
      }
    };
  }

  const d = item.json;

  const spec = {
    version: "v1",
    account_id: d.account_id || "",
    company_name: d.company_name || "",

    business_hours: {
      days: d.business_hours?.days || [],
      start: d.business_hours?.start || "",
      end: d.business_hours?.end || "",
      timezone: d.business_hours?.timezone || ""
    },

    office_address: d.office_address || "",

    services_supported: d.services_supported || [],

    emergency: {
      definition: d.emergency_definition || "",
      routing_rules: {
        primary: d.emergency_routing_rules?.primary || "",
        order: d.emergency_routing_rules?.order || [],
        fallback: d.emergency_routing_rules?.fallback || ""
      }
    },

    non_emergency: {
      routing_rules: d.non_emergency_routing_rules || ""
    },

    call_transfer: {
      timeout_seconds: d.call_transfer_rules?.timeout_seconds ?? null,
      retries: d.call_transfer_rules?.retries ?? null,
      message_if_fails: d.call_transfer_rules?.message_if_fails || ""
    },

    integration_constraints: d.integration_constraints || [],

    flow_summaries: {
      after_hours: d.after_hours_flow_summary || "",
      office_hours: d.office_hours_flow_summary || ""
    },

    questions_or_unknowns: d.questions_or_unknowns || [],
    notes: d.notes || "",

    meta: {
      source: "demo_call",
      spec_generated: true,
      generated_at: new Date().toISOString()
    }
  };

  return { json: spec };
});

const fs = require('fs');
const path = require('path');

const results = [];
for (const item of $input.all()) {
  const d = item.json;
  const account_id = d.account_id;

  // Build memo from parsed fields on item.json
  const memo = {
    account_id,
    company_name: d.company_name || '',
    business_hours: d.business_hours || { days: '', start: '', end: '', timezone: '' },
    office_address: d.office_address || '',
    services_supported: d.services_supported || [],
    emergency_definition: d.emergency_definition || [],
    emergency_routing_rules: d.emergency_routing_rules || { primary: '', order: [], fallback: '' },
    non_emergency_routing_rules: d.non_emergency_routing_rules || '',
    call_transfer_rules: d.call_transfer_rules || { timeout_seconds: null, retries: null, message_if_fails: '' },
    integration_constraints: d.integration_constraints || [],
    after_hours_flow_summary: d.after_hours_flow_summary || '',
    office_hours_flow_summary: d.office_hours_flow_summary || '',
    questions_or_unknowns: d.questions_or_unknowns || [],
    notes: d.notes || '',
    version: 'v1',
    source: 'demo_call',
  };

  const dir = `/outputs/accounts/${account_id}/v1`;
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'account_memo_v1.json'), JSON.stringify(memo, null, 2));
  results.push({ json: { account_id, saved_memo: true } });
}
return results;

const fs = require('fs');
const path = require('path');

const results = [];
for (const item of $input.all()) {
  const inputData = item.json;
  const account_id = inputData.account_id;
  const dir = `/outputs/accounts/${account_id}/v1`;
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'agent_spec_v1.json'), JSON.stringify(inputData, null, 2));
  results.push({ json: { account_id, saved_spec: true } });
}
return results;

const fs = require('fs');
const path = require('path');

const dir = '/data/transcripts/demo';
const allFiles = fs.readdirSync(dir);
const filtered = allFiles.filter(f => f.endsWith('.txt') && f !== '.gitkeep');

// This will show in the output so we can see what's being found
return filtered.map(filename => {
  const content = fs.readFileSync(path.join(dir, filename), 'utf8').replace(/^\uFEFF/, '').trim();
  const account_id = filename.replace('.txt', '');
  return { json: { account_id, transcript: content, filename, all_files_found: allFiles, filtered_files: filtered } };
});
